package main

import (
	"fmt"
	"os"
	"github.com/7mind/wanbond/internal/config"
)

func main() {
	cfg, err := config.Load("/tmp/test_multi_peer.toml")
	if err != nil {
		fmt.Printf("ERROR loading config: %v\n", err)
		os.Exit(1)
	}
	fmt.Printf("Config loaded successfully!\n")
	fmt.Printf("Role: %s\n", cfg.Role)
	fmt.Printf("Number of peers: %d\n", len(cfg.WireGuard.Peers))
	for i, p := range cfg.WireGuard.Peers {
		fmt.Printf("  Peer %d: name=%q has_psk=%v\n", i, p.Name, p.PSK.Set())
	}
}
EOF

nix develop -c sh -c 'go run /tmp/test_config.go 2>&1'
